select 
from drive_upload
where upload_id = #{uploadId, jdbcType=BINARY}

select 
from drive_upload
where status in ('COMPLETING', 'OBJECT_COMPLETED')
  and updated_at < #{updatedBefore}
order by updated_at asc, upload_id asc
limit #{limit}

mapper.update:
update drive_upload
set status = #{status},
    updated_at = #{updatedAt},
    completed_at = #{completedAt},
    completed_entry_id = #{completedEntryId, jdbcType=BINARY}
where upload_id = #{uploadId, jdbcType=BINARY}
  and space_id = #{spaceId, jdbcType=BINARY}

update drive_upload
set status = #{upload.status},
    updated_at = #{upload.updatedAt},
    completed_at = #{upload.completedAt},
    completed_entry_id = #{upload.completedEntryId, jdbcType=BINARY}
where upload_id = #{upload.uploadId, jdbcType=BINARY}
  and space_id = #{upload.spaceId, jdbcType=BINARY}
  and status = #{expectedStatus}
